function TableDemo() {
  const [sortDir, setSortDir] = useState('none');

  const handleSort = () => {
    setSortDir(d => d === 'ascending' ? 'descending' : 'ascending');
  };

  return (
    <table aria-label="직원 목록">
      <caption>2024년 직원 현황</caption>
      <thead>
        <tr>
          <th scope="col">
            <button
              onClick={handleSort}
              aria-sort={sortDir}
            >
              이름 {sortDir === 'ascending' ? '▲' : sortDir === 'descending' ? '▼' : '⇅'}
            </button>
          </th>
          <th scope="col">부서</th>
          <th scope="col">직급</th>
        </tr>
      </thead>
      <tbody>
        <tr>
          <td>홍길동</td>
          <td>개발팀</td>
          <td>시니어</td>
        </tr>
        <tr>
          <td>김철수</td>
          <td>디자인팀</td>
          <td>주니어</td>
        </tr>
      </tbody>
    </table>
  );
}
